leaderboard_router = APIRouter()

# ---------- Endpoints ----------
@leaderboard_router.get("/leaderboard", response_model=dict)
def list_leaderboard(
    limit: int = Query(50, ge=1, le=500),
    offset: int = Query(0, ge=0),
    search: str | None = Query(None, min_length=1),
    min_rating: float | None = Query(None, ge=0),
    max_rating: float | None = Query(None, ge=0),
    db: Session = Depends(get_db),
):
    query = db.query(LeaderboardEntry).join(Users, LeaderboardEntry.user_id == Users.id)
    if search:
        query = query.filter(Users.display_name.ilike(f"%{search}%"))
    if min_rating is not None:
        query = query.filter(LeaderboardEntry.rating >= min_rating)
    if max_rating is not None:
        query = query.filter(LeaderboardEntry.rating <= max_rating)

    total = query.with_entities(func.count(LeaderboardEntry.id)).scalar()
    entries = query.offset(offset).limit(limit).all()
    return {"items": [entry.__dict__ for entry in entries], "total": total}

@leaderboard_router.get("/leaderboard/{entry_id}", response_model=dict)
def get_leaderboard_entry(
    entry_id: int = Path(..., ge=1),
    db: Session = Depends(get_db),
):
    entry = db.query(LeaderboardEntry).filter(LeaderboardEntry.id == entry_id).first()
    if not entry:
        raise HTTPException(status_code=404, detail="Not found")
    return entry.__dict__

@leaderboard_router.post("/leaderboard", response_model=dict, status_code=status.HTTP_201_CREATED)
def create_leaderboard_entry(
    payload: LeaderboardCreate,
    db: Session = Depends(get_db),
):
    # Ensure the referenced user exists
    user = db.query(Users).filter(Users.id == payload.user_id).first()
    if not user:
        raise HTTPException(status_code=404, detail="User not found")
    entry = LeaderboardEntry(
        user_id=payload.user_id,
        wins=payload.wins,
        losses=payload.losses,
        rating=payload.rating,
    )
    db.add(entry)
    db.commit()
    db.refresh(entry)
    return entry.__dict__

@leaderboard_router.put("/leaderboard/{entry_id}", response_model=dict)
def update_leaderboard_entry(
    payload: LeaderboardUpdate,
    entry_id: int = Path(..., ge=1),
    db: Session = Depends(get_db),
):
    entry = db.query(LeaderboardEntry).filter(LeaderboardEntry.id == entry_id).first()
    if not entry:
        raise HTTPException(status_code=404, detail="Not found")
    if payload.wins is not None:
        entry.wins = payload.wins
    if payload.losses is not None:
        entry.losses = payload.losses
    if payload.rating is not None:
        entry.rating = payload.rating
    db.commit()
    db.refresh(entry)
    return entry.__dict__

@leaderboard_router.delete("/leaderboard/{entry_id}", status_code=status.HTTP_204_NO_CONTENT)
